df = pd.read_csv(
    "/content/Amazon_Reviews.csv.zip",
    engine="python",
    quoting=csv.QUOTE_MINIMAL
)

print(
    "Duplicate Rows:",
    df.duplicated().sum()
)

df = df.drop_duplicates(
    subset=["Review Text"],
    keep="first"
).reset_index(drop=True)

df = df.dropna(subset=["Review Text", "Rating"])

df

def convert_rating(r):

    if r <= 2:
        return 0

    elif r == 3:
        return 1

    else:
        return 2

rating_map = {
    "Rated 1 out of 5 stars": 1,
    "Rated 2 out of 5 stars": 2,
    "Rated 3 out of 5 stars": 3,
    "Rated 4 out of 5 stars": 4,
    "Rated 5 out of 5 stars": 5
}

df["rating_num"] = df["Rating"].map(rating_map)

df["label"] = df["rating_num"].apply(convert_rating)
for label in [0,1,2]:

    print(f"\nLABEL {label}")

    sample = df[
        df["label"] == label
    ].sample(20, random_state=42)

    for text in sample["Review Text"]:

        print(text[:200])
        print("-"*50)

df_original = df[["Review Text","label"]]

df.info()

df_original

