"""# METRICS COMPUTING"""

from sklearn.metrics import (
    accuracy_score,
    precision_recall_fscore_support
)

def compute_metrics(eval_pred):

    logits, labels = eval_pred

    preds = np.argmax(
        logits,
        axis=1
    )

    precision_w, recall_w, f1_w, _ = \
        precision_recall_fscore_support(
            labels,
            preds,
            average="weighted"
        )

    precision_m, recall_m, f1_m, _ = \
        precision_recall_fscore_support(
            labels,
            preds,
            average="macro"
        )

    acc = accuracy_score(
        labels,
        preds
    )

    return {

        "accuracy": acc,

        "weighted_precision": precision_w,
        "weighted_recall": recall_w,
        "weighted_f1": f1_w,

        "macro_precision": precision_m,
        "macro_recall": recall_m,
        "macro_f1": f1_m
    }

steps_per_epoch = len(train_ds) // 16

total_steps = steps_per_epoch * 5

warmup_steps = int(total_steps * 0.1)

