"""# Compute Expected Calibration Error (ECE)"""

import numpy as np

def expected_calibration_error(y_true,
                               y_pred,
                               confidence,
                               n_bins=10):

    bins = np.linspace(0, 1, n_bins + 1)

    ece = 0

    for i in range(n_bins):

        mask = (
            (confidence > bins[i])
            &
            (confidence <= bins[i+1])
        )

        if np.sum(mask) > 0:

            acc = np.mean(
                y_true[mask] == y_pred[mask]
            )

            conf = np.mean(
                confidence[mask]
            )

            ece += (
                np.sum(mask)
                / len(confidence)
            ) * abs(acc - conf)

    return ece

ece = expected_calibration_error(
    y_true,
    y_pred,
    confidence
)

print("ECE:", ece)

